-- Create "promo_codes" table
CREATE TABLE "promo_codes" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "code" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'active',
  "discount_type" character varying NOT NULL,
  "discount_value" character varying NOT NULL DEFAULT '0.00000000',
  "currency" character varying NOT NULL DEFAULT 'USD',
  "max_uses" bigint NOT NULL DEFAULT 1,
  "per_user_limit" bigint NOT NULL DEFAULT 0,
  "min_order_amount" character varying NOT NULL DEFAULT '',
  "used_count" bigint NOT NULL DEFAULT 0,
  "starts_at" timestamptz NULL,
  "expires_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "promocode_code" to table: "promo_codes"
CREATE UNIQUE INDEX "promocode_code" ON "promo_codes" ("code");
-- Create index "promocode_expires_at" to table: "promo_codes"
CREATE INDEX "promocode_expires_at" ON "promo_codes" ("expires_at");
-- Create index "promocode_status_created_at" to table: "promo_codes"
CREATE INDEX "promocode_status_created_at" ON "promo_codes" ("status", "created_at");
-- Create "redeem_codes" table
CREATE TABLE "redeem_codes" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "code" character varying NOT NULL,
  "type" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'active',
  "value" character varying NOT NULL DEFAULT '',
  "currency" character varying NOT NULL DEFAULT 'USD',
  "max_redemptions" bigint NOT NULL DEFAULT 1,
  "redeemed_count" bigint NOT NULL DEFAULT 0,
  "expires_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "redeemcode_code" to table: "redeem_codes"
CREATE UNIQUE INDEX "redeemcode_code" ON "redeem_codes" ("code");
-- Create index "redeemcode_expires_at" to table: "redeem_codes"
CREATE INDEX "redeemcode_expires_at" ON "redeem_codes" ("expires_at");
-- Create index "redeemcode_status_created_at" to table: "redeem_codes"
CREATE INDEX "redeemcode_status_created_at" ON "redeem_codes" ("status", "created_at");
